// 1. Dynamically establish date boundaries for Today, Current Week, and Current Month
const today = new Date();

// Daily Boundaries (Today at 00:00:00 to Today at 23:59:59)
const startOfToday = new Date(today);
startOfToday.setHours(0, 0, 0, 0);

const endOfToday = new Date(today);
endOfToday.setHours(23, 59, 59, 999);

// Current Week Boundaries (Sunday at 00:00:00 to Saturday at 23:59:59)
const currentDay = today.getDay();
const startOfWeek = new Date(today);
startOfWeek.setDate(today.getDate() - currentDay);
startOfWeek.setHours(0, 0, 0, 0);

const endOfWeek = new Date(today);
endOfWeek.setDate(today.getDate() - currentDay + 6);
endOfWeek.setHours(23, 59, 59, 999);

// Current Month Boundaries (1st day to last day of the current month)
const startOfMonth = new Date(today.getFullYear(), today.getMonth(), 1, 0, 0, 0, 0);
const endOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0, 23, 59, 59, 999);

// 2. Fetch all combined data passing out of your Merge node
const allData = $input.all();

// 3. Initialize all counters
let totalTickets = 0;
let totalServer = 0;
let totalNetwork = 0;

let monthlyServer = 0;
let monthlyNetwork = 0;
let monthlyTotalTickets = 0;

let weeklyServerResolved = 0;
let weeklyNetworkResolved = 0;
let weeklyNetworkInProgress = 0;
let weeklyServerInProgress = 0;

let dailyServerResolved = 0;
let dailyNetworkResolved = 0;
let dailyNetworkInProgress = 0;
let dailyServerInProgress = 0;

// 4. Process each ticket row
for (const item of allData) {
  const row = item.json;
  if (!row.Date) continue;

  const ticketDate = new Date(row.Date);
  const deviceType = String(row['Device Type'] || '').trim().toLowerCase();
  const status = String(row.Status || '').trim().toLowerCase();

  // RULE: Completely exclude Cancelled tickets from being processed/counted
  if (status === 'cancelled') continue;

  // Safe matching handling for trailing whitespaces
  const isServer = deviceType.includes('server');
  const isNetwork = deviceType.includes('network');

  // RULE 1: Map groups into Resolved vs Closed
  const isResolved = ['resolved', 'closed'].includes(status);

  // RULE 2: Separate In-Progress text conditions based on device types
  let isInProgress = false;
  if (isNetwork) {
    isInProgress = ['in progress', 'endorse to enterprise support', 'monitoring'].includes(status);
  } else if (isServer) {
    isInProgress = ['work in progress', 'waiting for support'].includes(status);
  }

  // Check which timestamp windows the ticket matches
  const inCurrentDay = (ticketDate >= startOfToday && ticketDate <= endOfToday);
  const inCurrentWeek = (ticketDate >= startOfWeek && ticketDate <= endOfWeek);
  const inCurrentMonth = (ticketDate >= startOfMonth && ticketDate <= endOfMonth);

  // --- OVERALL METRICS ---
  if (isServer || isNetwork) {
    totalTickets++;
    if (isServer) totalServer++;
    if (isNetwork) totalNetwork++;
  }

  // --- DAILY METRICS ---
  if (inCurrentDay) {
    if (isServer && isResolved) dailyServerResolved++;
    if (isNetwork && isResolved) dailyNetworkResolved++;

    if (isNetwork && isInProgress) dailyNetworkInProgress++;
    if (isServer && isInProgress) dailyServerInProgress++;
  }

  // --- WEEKLY METRICS ---
  if (inCurrentWeek) {
    if (isServer && isResolved) weeklyServerResolved++;
    if (isNetwork && isResolved) weeklyNetworkResolved++;

    if (isNetwork && isInProgress) weeklyNetworkInProgress++;
    if (isServer && isInProgress) weeklyServerInProgress++;
  }

  // --- MONTHLY METRICS ---
  if (inCurrentMonth) {
    if (isServer) monthlyServer++;
    if (isNetwork) monthlyNetwork++;
    if (isServer || isNetwork) monthlyTotalTickets++;
  }
}

// --- DYNAMIC MATH COHESION ENGINE ---
const dailyServerTotal = dailyServerResolved + dailyServerInProgress;
const dailyNetworkTotal = dailyNetworkResolved + dailyNetworkInProgress;
const dailyTotalTicketsCombined = dailyServerTotal + dailyNetworkTotal;

const weeklyServerTotal = weeklyServerResolved + weeklyServerInProgress;
const weeklyNetworkTotal = weeklyNetworkResolved + weeklyNetworkInProgress;
const weeklyCombinedResolved = weeklyServerResolved + weeklyNetworkResolved;
const weeklyCombinedInProgress = weeklyServerInProgress + weeklyNetworkInProgress;
const weeklyTotalTicketsCombined = weeklyCombinedResolved + weeklyCombinedInProgress;

// 5. Format and return array mapped rows out to the Google Sheet dashboard node
return [
  { json: { Label: "📊 GLOBAL MONITORING STATS", Value: "" } }, 
  { json: { Label: "Total Number of Tickets", Value: totalTickets } }, 
  { json: { Label: "Total Device Type: Server", Value: totalServer } }, 
  { json: { Label: "Total Device Type: Network", Value: totalNetwork } }, 
  { json: { Label: "---", Value: "---" } }, 

  { json: { Label: "📅 WEEKLY STATS (Current Week)", Value: "" } }, 
  { json: { Label: "Weekly Total Tickets (Combined)", Value: weeklyTotalTicketsCombined } }, 
  { json: { Label: "Weekly Servers Monitored", Value: weeklyServerTotal } }, 
  { json: { Label: "Weekly Networks Monitored", Value: weeklyNetworkTotal } }, 
  { json: { Label: "Weekly Servers Resolved", Value: weeklyServerResolved } }, 
  { json: { Label: "Weekly Networks Resolved", Value: weeklyNetworkResolved } }, 
  { json: { Label: "Weekly Servers In Progress", Value: weeklyServerInProgress } }, 
  { json: { Label: "Weekly Networks In Progress", Value: weeklyNetworkInProgress } }, 
  { json: { Label: "Weekly Total Resolved (Combined)", Value: weeklyCombinedResolved } }, 
  { json: { Label: "Weekly Total In Progress (Combined)", Value: weeklyCombinedInProgress } }, 
  { json: { Label: "---", Value: "---" } }, 

  { json: { Label: "🗓️ MONTHLY STATS (Current Month)", Value: "" } }, 
  { json: { Label: "Monthly Total Tickets (Combined)", Value: monthlyTotalTickets } }, 
  { json: { Label: "Monthly Servers Monitored", Value: monthlyServer } }, 
  { json: { Label: "Monthly Networks Monitored", Value: monthlyNetwork } },
  { json: { Label: "---", Value: "---" } }, 

  { json: { Label: "☀️ DAILY STATS (Today)", Value: "" } }, 
  { json: { Label: "Daily Total Tickets (Combined)", Value: dailyTotalTicketsCombined } }, 
  { json: { Label: "Daily Servers Monitored", Value: dailyServerTotal } }, 
  { json: { Label: "Daily Servers In Progress", Value: dailyServerInProgress } }, 
  { json: { Label: "Daily Servers Resolved", Value: dailyServerResolved } }, 
  { json: { Label: "Daily Networks Monitored", Value: dailyNetworkTotal } }, 
  { json: { Label: "Daily Networks Resolved", Value: dailyNetworkResolved } }, 
  { json: { Label: "Daily Networks In Progress", Value: dailyNetworkInProgress } } 
];

